package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void testDisableJdkUnsafe_shouldSetUseJdkUnsafeToFalseAndReturnThis() throws Exception {
    // Verify initial state is true (default)
    Field useJdkUnsafeField = GsonBuilder.class.getDeclaredField("useJdkUnsafe");
    useJdkUnsafeField.setAccessible(true);
    boolean initialValue = (boolean) useJdkUnsafeField.get(gsonBuilder);
    assertTrue(initialValue, "Initial useJdkUnsafe should be true");

    // Call disableJdkUnsafe
    GsonBuilder returned = gsonBuilder.disableJdkUnsafe();

    // Verify the field is set to false
    boolean updatedValue = (boolean) useJdkUnsafeField.get(gsonBuilder);
    assertFalse(updatedValue, "useJdkUnsafe should be false after disableJdkUnsafe");

    // Verify the method returns the same instance
    assertSame(gsonBuilder, returned, "disableJdkUnsafe should return the same GsonBuilder instance");
  }
}
